INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2023/12/15 15:00:00", 0.0, 129602, -470.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", "2024/03/22 14:59:59", 1, 2, 0.0, "アネモネ", 3, 10009);
