INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2023/12/15 15:00:00", 0.0, 129701, -470.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", "2024/03/22 14:59:59", 1, 1, 0.0, "ネフィ=ネラ", 3, 10011);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2023/12/15 15:00:00", 0.0, 129701, -470.0, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", "2024/03/22 14:59:59", 1, 2, 6.2, "ネフィ=ネラ", 3, 10012);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/03/15 15:00:00", 0.0, 130301, -470.0, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", "2024/06/22 14:59:59", 5, 3, 3.1, "カノン", 4, 10013);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2024/03/15 15:00:00", 0.0, 130301, -470.0, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", "2024/06/22 14:59:59", 2, 3, 6.15, "カノン", 4, 10014);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/03/15 15:00:00", 0.0, 130401, -470.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", "2024/06/22 14:59:59", 2, 2, 0.0, "ナーナ", 4, 10015);
