INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/06/15 15:00:00", 0.0, 130502, -470.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", "2024/09/22 14:59:59", 1, 1, 0.0, "ホウオウ", 5, 10017);
