INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 3, "2024/06/15 15:00:00", 0.0, 130503, -470.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", "2024/09/22 14:59:59", 4, 4, 0.0, "ホウオウ", 5, 10019);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/06/15 15:00:00", 0.0, 123301, -470.0, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", "2024/09/22 14:59:59", 2, 1, 4.9, "ネア", 5, 10020);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2024/06/15 15:00:00", 0.0, 123301, -470.0, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", "2024/09/22 14:59:59", 2, 1, 4.8, "ネア", 5, 10021);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/09/15 15:00:00", 0.0, 133301, -470.0, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", "2024/12/22 14:59:59", 1, 3, 4.922, "カリザ", 6, 10022);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2024/09/15 15:00:00", 0.0, 133301, -470.0, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", "2024/12/22 14:59:59", 5, 3, 9.638, "カリザ", 6, 10023);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/09/15 15:00:00", 0.0, 133401, -470.0, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", "2024/12/22 14:59:59", 2, 1, 2.88, "ミーア", 6, 10024);
