INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/12/15 15:00:00", 0.0, 133002, -470.0, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", "2025/03/22 14:59:59", 1, 2, 1.78, "グレイス", 7, 10026);
