INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2024/12/15 15:00:00", 0.0, 133102, -470.0, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", "2025/03/22 14:59:59", 2, 6, 4.28, "ヴァイオレット", 7, 10028);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2024/12/15 15:00:00", 0.0, 133102, -470.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", "2025/03/22 14:59:59", 1, 1, 0.0, "ヴァイオレット", 7, 10029);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/03/15 15:00:00", 0.0, 136902, -470.0, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", "2025/06/23 14:59:59", 1, 2, 5.53, "ルルィ", 8, 10030);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/03/15 15:00:00", 0.0, 136902, -470.0, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", "2025/06/23 14:59:59", 7, 9, 6.05, "ルルィ", 8, 10031);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/03/15 15:00:00", 0.0, 137001, -470.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", "2025/06/23 14:59:59", 1, 2, 0.0, "デュラン", 8, 10032);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/03/15 15:00:00", 0.0, 137001, -470.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", "2025/06/23 14:59:59", 1, 2, 0.0, "デュラン", 8, 10033);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/06/16 15:00:00", 0.0, 135902, -470.0, "おう\n好きなもん持ってきな", "2025/09/23 14:59:59", 2, 2, 0.0, "サツキ", 9, 10034);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/06/16 15:00:00", 0.0, 135902, -470.0, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", "2025/09/23 14:59:59", 6, 1, 4.935, "サツキ", 9, 10035);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/06/16 15:00:00", 0.0, 135802, -470.0, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", "2025/09/23 14:59:59", 5, 2, 7.441, "ユキノ", 9, 10036);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/06/16 15:00:00", 0.0, 135802, -470.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", "2025/09/23 14:59:59", 7, 7, 0.0, "ユキノ", 9, 10037);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/09/16 15:00:00", 0.0, 130901, -470.0, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", "2025/12/22 14:59:59", 2, 2, 2.295, "クルル", 10, 10038);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/09/16 15:00:00", 0.0, 130901, -470.0, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", "2025/12/22 14:59:59", 6, 1, 6.281, "クルル", 10, 10039);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/09/16 15:00:00", 0.0, 137701, -470.0, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", "2025/12/22 14:59:59", 1, 2, 5.549, "ヴォルガーノ", 10, 10040);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/09/16 15:00:00", 0.0, 137701, -470.0, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", "2025/12/22 14:59:59", 6, 3, 2.64, "ヴォルガーノ", 10, 10041);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/12/15 15:00:00", 0.0, 132801, -470.0, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", "2026/03/23 11:59:59", 4, 7, 7.642, "ライラエル", 11, 10042);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/12/15 15:00:00", 0.0, 132802, -470.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", "2026/03/23 11:59:59", 1, 1, 0.0, "ライラエル", 11, 10043);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2025/12/15 15:00:00", 0.0, 134502, -470.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", "2026/03/23 11:59:59", 1, 1, 0.0, "クローチェ", 11, 10044);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2025/12/15 15:00:00", 0.0, 134501, -470.0, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", "2026/03/23 11:59:59", 1, 2, 3.72, "クローチェ", 11, 10045);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2026/03/16 12:00:00", 0.0, 138201, -470.0, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", "2026/06/22 11:59:59", 1, 2, 4.991, "ネフィ＝ネラ", 12, 10046);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2026/03/16 12:00:00", 0.0, 138201, -470.0, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", "2026/06/22 11:59:59", 4, 1, 3.877, "ネフィ＝ネラ", 12, 10047);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 1, "2026/03/16 12:00:00", 0.0, 136001, -470.0, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", "2026/06/22 11:59:59", 6, 4, 1.71, "アラクネ", 12, 10048);
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2002, 2, "2026/03/16 12:00:00", 0.0, 136001, -470.0, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", "2026/06/22 11:59:59", 2, 5, 5.32, "アラクネ", 12, 10049);
